useEffect(() => {
  if (!currentProduct?.slug) {
    return;
  }

  // Client-only view tracking with simple throttling.
  if (typeof window === "undefined") {
    return;
  }

  try {
    const key = `productView:${currentProduct.slug}`;
    const lastRaw = window.localStorage.getItem(key);
    const last = Number(lastRaw);
    const now = Date.now();

    // 30 min cooldown per device per product.
    if (Number.isFinite(last) && now - last < 30 * 60 * 1000) {
      return;
    }

    window.localStorage.setItem(key, String(now));

    fetch("/api/product-views", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ slug: currentProduct.slug }),
    }).catch((error) => {
      console.error("Could not record product view", error);
    });
  } catch (error) {
    console.error("Could not record product view", error);
  }
}, [currentProduct?.slug]);

